// ── Design tokens ─────────────────────────────────────────────────────────────
const PLAID_BLACK  = '#0d1117';
const PLAID_WHITE  = '#ffffff';
const PLAID_TEAL   = '#00A67E';
const PLAID_BLUE   = '#1D4ED8';
const FONT_STACK   = 'system-ui, -apple-system, "Helvetica Neue", Arial, sans-serif';

// ── Reusable fade helper ──────────────────────────────────────────────────────
function useFade(frame, inStart, inEnd, outStart, outEnd) {
  return interpolate(
    frame,
    [inStart, inEnd, outStart, outEnd],
    [0, 1, 1, 0],
    { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' }
  );
}

// ── Intro Title Card ──────────────────────────────────────────────────────────
function IntroCard({ frame }) {
  const opacity = useFade(frame, 0, 20, 65, 85);
  const y = interpolate(frame, [0, 20], [30, 0], { extrapolateRight: 'clamp' });

  return (
    <AbsoluteFill
      style={{
        background: `linear-gradient(135deg, ${PLAID_BLACK} 0%, #0a2540 100%)`,
        justifyContent: 'center',
        alignItems: 'center',
        opacity,
      }}
    >
      <div style={{ textAlign: 'center', transform: `translateY(${y}px)` }}>
        {/* Plaid wordmark */}
        <div style={{
          color: PLAID_TEAL,
          fontFamily: FONT_STACK,
          fontWeight: 700,
          fontSize: 22,
          letterSpacing: 6,
          textTransform: 'uppercase',
          marginBottom: 20,
          opacity: 0.9,
        }}>
          PLAID
        </div>
        <div style={{
          color: PLAID_WHITE,
          fontFamily: FONT_STACK,
          fontWeight: 700,
          fontSize: 68,
          lineHeight: 1.1,
          marginBottom: 16,
        }}>
          Identity Verification
        </div>
        <div style={{
          color: 'rgba(255,255,255,0.55)',
          fontFamily: FONT_STACK,
          fontWeight: 400,
          fontSize: 26,
        }}>
          KYC · Fraud Prevention · Compliance
        </div>
      </div>
    </AbsoluteFill>
  );
}

// ── Step Label (lower-third) ──────────────────────────────────────────────────
function StepLabel({ label, frame, relFrame, durationFrames }) {
  const opacity = useFade(relFrame, 0, 12, durationFrames - 15, durationFrames - 3);
  const x = interpolate(relFrame, [0, 12], [-20, 0], { extrapolateRight: 'clamp' });

  return (
    <div style={{
      position: 'absolute',
      bottom: 36,
      left: 48,
      opacity,
      transform: `translateX(${x}px)`,
      display: 'flex',
      alignItems: 'center',
      gap: 10,
      pointerEvents: 'none',
    }}>
      <div style={{
        width: 4,
        height: 28,
        background: PLAID_TEAL,
        borderRadius: 2,
      }} />
      <div style={{
        background: 'rgba(0,0,0,0.72)',
        backdropFilter: 'blur(8px)',
        color: PLAID_WHITE,
        fontFamily: FONT_STACK,
        fontWeight: 600,
        fontSize: 17,
        padding: '7px 16px',
        borderRadius: 8,
        letterSpacing: 0.3,
      }}>
        {label}
      </div>
    </div>
  );
}

