// ── Main composition ──────────────────────────────────────────────────────────
const DemoComposition = () => {
  const frame = useCurrentFrame();
  const { durationInFrames } = useVideoConfig();

  const INTRO_DURATION = 90;  // 3s intro card
  const OUTRO_START    = STEP_TIMING[STEP_TIMING.length - 1]?.startFrame ?? (durationInFrames - 180);
  const OUTRO_DURATION = durationInFrames - OUTRO_START;

  // Find which step we're currently in (for step labels + overlays)
  const currentStep = STEP_TIMING.find(
    s => frame >= s.startFrame && frame < (s.endFrame ?? durationInFrames)
  );

  // Video fade-in from black
  const videoOpacity = interpolate(frame, [0, 15], [0, 1], { extrapolateRight: 'clamp' });
  // Video fade-out to outro
  const videoFadeOut = interpolate(frame, [OUTRO_START - 20, OUTRO_START], [1, 0], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
  });
  const videoVis = Math.min(videoOpacity, videoFadeOut);

  return (
    <AbsoluteFill style={{ background: PLAID_BLACK, overflow: 'hidden' }}>

      {/* ── Base video ── */}
      <AbsoluteFill style={{ opacity: videoVis }}>
        <OffthreadVideo
          src={staticFile('recording.webm')}
          style={{ width: '100%', height: '100%', objectFit: 'contain' }}
          volume={0}
        />
      </AbsoluteFill>

      {/* ── Voiceover audio (full track, synced to video) ── */}
      <Audio src={staticFile('voiceover.mp3')} volume={1} />

      {/* ── Intro title card (first 3s) ── */}
      {frame < INTRO_DURATION && (
        <IntroCard frame={frame} />
      )}

      {/* ── Plaid watermark (visible after intro, before outro) ── */}
      {frame >= INTRO_DURATION && frame < OUTRO_START && (
        <PlaidWatermark />
      )}

      {/* ── Step label lower-thirds ── */}
      {currentStep && frame >= INTRO_DURATION && frame < OUTRO_START && (
        <Sequence from={currentStep.startFrame} durationInFrames={currentStep.endFrame - currentStep.startFrame}>
          <StepLabel
            label={currentStep.label}
            frame={frame}
            relFrame={frame - currentStep.startFrame}
            durationFrames={currentStep.endFrame - currentStep.startFrame}
          />
        </Sequence>
      )}

      {/* ── Trust Index Badge — step 09a ── */}
      {(() => {
        const s = STEP_TIMING.find(x => x.id === '09a-dashboard');
        if (!s || frame < s.startFrame || frame >= s.endFrame) return null;
        const rel = frame - s.startFrame;
        const dur = s.endFrame - s.startFrame;
        return <TrustIndexBadge frame={frame} relFrame={rel} durationFrames={dur} />;
      })()}

      {/* ── Match Callout — step 09c ── */}
      {(() => {
        const s = STEP_TIMING.find(x => x.id === '09c-data-source');
        if (!s || frame < s.startFrame || frame >= s.endFrame) return null;
        const rel = frame - s.startFrame;
        const dur = s.endFrame - s.startFrame;
        return <MatchCallout relFrame={rel} durationFrames={dur} />;
      })()}

      {/* ── Watchlist Badge — step 09d ── */}
      {(() => {
        const s = STEP_TIMING.find(x => x.id === '09d-watchlist');
        if (!s || frame < s.startFrame || frame >= s.endFrame) return null;
        const rel = frame - s.startFrame;
        const dur = s.endFrame - s.startFrame;
        return <WatchlistBadge relFrame={rel} durationFrames={dur} />;
      })()}

      {/* ── Risk Callout — step 09e ── */}
      {(() => {
        const s = STEP_TIMING.find(x => x.id === '09e-risk-check');
        if (!s || frame < s.startFrame || frame >= s.endFrame) return null;
        const rel = frame - s.startFrame;
        const dur = s.endFrame - s.startFrame;
        return <RiskCallout relFrame={rel} durationFrames={dur} />;
      })()}

      {/* ── Outro CTA card (last step) ── */}
      {frame >= OUTRO_START && (
        <OutroCard
          frame={frame}
          relFrame={frame - OUTRO_START}
          durationFrames={OUTRO_DURATION}
        />
      )}

    </AbsoluteFill>
  );
};

module.exports = { DemoComposition };
